1	use gloo_storage::Storage;
2	use leptos::*;
3	
4	#[derive(Clone, Copy)]
5	pub struct AuthState {
6	    pub token: ReadSignal<Option<String>>,
7	    pub set_token: WriteSignal<Option<String>>,
8	    pub user: ReadSignal<Option<common::UserProfile>>,
9	    pub set_user: WriteSignal<Option<common::UserProfile>>,
10	}
11	
12	impl AuthState {
13	    pub fn login(&self, token: String, user: common::UserProfile) {
14	        let _ = gloo_storage::LocalStorage::set("auth_token", &token);
15	        let _ = gloo_storage::LocalStorage::set("current_user", &user);
16	        self.set_token.set(Some(token));
17	        self.set_user.set(Some(user));
18	    }
19	
20	    pub fn logout(&self) {
21	        gloo_storage::LocalStorage::delete("auth_token");
22	        gloo_storage::LocalStorage::delete("current_user");
23	        self.set_token.set(None);
24	        self.set_user.set(None);
25	    }
26	
27	    pub fn is_logged_in(&self) -> bool {
28	        self.token.get().is_some()
29	    }
30	
31	    pub fn get_token(&self) -> Option<String> {
32	        self.token.get()
33	    }
34	}
