6	#[component]
7	pub fn NotificationCenter() -> impl IntoView {
8	    let auth = use_context::<AuthState>().unwrap();
9	    let (refresh, set_refresh) = create_signal(0u32);
10	
11	    let notifications = create_resource(
12	        move || (auth.get_token(), refresh.get()),
13	        |(token, _)| async move {
14	            match token {
15	                Some(t) => api::list_notifications(&t).await.ok(),
16	                None => None,
17	            }
18	        },
19	    );
20	
21	    let mark_all = move |_| {
22	        if let Some(token) = auth.get_token() {
23	            spawn_local(async move {
24	                let _ = api::mark_all_read(&token).await;
25	                set_refresh.update(|c| *c += 1);
26	            });
27	        }
28	    };
29	
30	    view! {
31	        <div class="notification-center">
32	            <div class="notif-header">
33	                <h3>"Message Center"</h3>
34	                <button class="btn btn-sm" on:click=mark_all>"Mark All Read"</button>
35	            </div>
36	            <Suspense fallback=move || view! { <p>"Loading..."</p> }>
37	                {move || notifications.get().map(|data| match data {
38	                    Some(list) if !list.is_empty() => {
39	                        let unread_count = list.iter().filter(|n| !n.is_read).count();
40	                        view! {
41	                            <div class="notif-summary">
42	                                {format!("{} unread of {} total", unread_count, list.len())}
43	                            </div>
44	                            <div class="notif-list">
45	                                {list.into_iter().map(|n| {
46	                                    let nid = n.id.clone();
47	                                    let is_read = n.is_read;
48	                                    let on_click = move |_| {
49	                                        if !is_read {
50	                                            let nid = nid.clone();
51	                                            if let Some(token) = auth.get_token() {
52	                                                spawn_local(async move {
53	                                                    let _ = api::mark_notification_read(&token, &nid).await;
54	                                                    set_refresh.update(|c| *c += 1);
55	                                                });
56	                                            }
57	                                        }
58	                                    };
59	                                    view! {
60	                                        <div class={if n.is_read { "notif-item read" } else { "notif-item unread" }}
61	                                            on:click=on_click>
62	                                            <div class="notif-title">{&n.title}</div>
63	                                            <div class="notif-body">{&n.body}</div>
64	                                            <div class="notif-time">{&n.created_at}</div>
65	                                        </div>
66	                                    }
67	                                }).collect::<Vec<_>>()}
68	                            </div>
69	                        }.into_view()
70	                    }
71	                    _ => view! {
72	                        <p class="empty">"No notifications."</p>
73	                    }.into_view(),
74	                })}
75	            </Suspense>
76	        </div>
77	    }
78	}
