1	use argon2::{
2	    password_hash::{rand_core::OsRng, PasswordHash, PasswordHasher, PasswordVerifier, SaltString},
3	    Argon2,
4	};
5	use hmac::{Hmac, Mac};
6	use sha2::Sha256;
7	use base64::{engine::general_purpose::URL_SAFE_NO_PAD, Engine};
8	
9	type HmacSha256 = Hmac<Sha256>;
10	
11	/// Hash a password with argon2 + random salt.
12	pub fn hash_password(password: &str) -> Result<String, String> {
13	    let salt = SaltString::generate(&mut OsRng);
14	    let argon2 = Argon2::default();
15	    argon2
16	        .hash_password(password.as_bytes(), &salt)
17	        .map(|h| h.to_string())
18	        .map_err(|e| e.to_string())
19	}
20	
21	/// Verify a password against an argon2 hash.
22	pub fn verify_password(password: &str, hash: &str) -> bool {
23	    let parsed = match PasswordHash::new(hash) {
24	        Ok(h) => h,
25	        Err(_) => return false,
26	    };
27	    Argon2::default()
28	        .verify_password(password.as_bytes(), &parsed)
29	        .is_ok()
30	}
31	
32	/// Create a signed session token: base64(user_id|expires_epoch)|signature
33	pub fn create_session_token(user_id: &str, secret: &[u8], ttl_secs: u64) -> String {
34	    let expires = std::time::SystemTime::now()
35	        .duration_since(std::time::UNIX_EPOCH)
36	        .unwrap()
37	        .as_secs()
38	        + ttl_secs;
39	    let payload = format!("{}|{}", user_id, expires);
40	    let encoded = URL_SAFE_NO_PAD.encode(payload.as_bytes());
41	
42	    let mut mac = HmacSha256::new_from_slice(secret).expect("HMAC key");
43	    mac.update(encoded.as_bytes());
44	    let sig = hex::encode(mac.finalize().into_bytes());
45	
46	    format!("{}.{}", encoded, sig)
47	}
48	
49	/// Validate a signed session token, returning the user_id if valid.
50	pub fn validate_session_token(token: &str, secret: &[u8]) -> Option<String> {
51	    let parts: Vec<&str> = token.splitn(2, '.').collect();
52	    if parts.len() != 2 {
53	        return None;
54	    }
55	    let (encoded, sig) = (parts[0], parts[1]);
56	
57	    // Verify signature
58	    let mut mac = HmacSha256::new_from_slice(secret).expect("HMAC key");
59	    mac.update(encoded.as_bytes());
60	    let expected_sig = hex::encode(mac.finalize().into_bytes());
61	    if sig != expected_sig {
62	        return None;
63	    }
64	
65	    // Decode payload
66	    let decoded = URL_SAFE_NO_PAD.decode(encoded).ok()?;
67	    let payload = String::from_utf8(decoded).ok()?;
68	    let parts: Vec<&str> = payload.splitn(2, '|').collect();
69	    if parts.len() != 2 {
70	        return None;
71	    }
72	
73	    let expires: u64 = parts[1].parse().ok()?;
74	    let now = std::time::SystemTime::now()
75	        .duration_since(std::time::UNIX_EPOCH)
76	        .unwrap()
77	        .as_secs();
78	
79	    if now > expires {
80	        return None; // Token expired
81	    }
82	
83	    Some(parts[0].to_string())
84	}
85	
86	/// Generate a short-lived nonce (random hex string).
87	pub fn generate_nonce() -> String {
88	    use rand::Rng;
89	    let bytes: [u8; 16] = rand::thread_rng().gen();
90	    hex::encode(bytes)
91	}
