82	        .await
83	        .map_err(|_| (StatusCode::BAD_REQUEST, Json(ApiError { error: "Invalid body".into() })))?;
84	    let req: GenerateCheckpointCodeRequest = serde_json::from_slice(&body)
85	        .map_err(|e| (StatusCode::BAD_REQUEST, Json(ApiError { error: e.to_string() })))?;
86	
87	    // Ownership check via fulfillment's project
88	    let project_id = db::get_fulfillment_project_id(&state.db, &req.fulfillment_id)
89	        .ok_or_else(|| (StatusCode::NOT_FOUND, Json(ApiError { error: "Fulfillment not found".into() })))?;
90	    require_project_owner(&state.db, &auth.user_id, &project_id)
91	        .map_err(|s| (s, Json(ApiError { error: "You do not manage this fulfillment's project".into() })))?;
92	
93	    use rand::Rng;
94	    let code: String = format!("{:06}", rand::thread_rng().gen_range(0..1_000_000));
95	
96	    let expires_at = chrono::Utc::now()
97	        .checked_add_signed(chrono::Duration::minutes(10))
98	        .unwrap()
99	        .format("%Y-%m-%d %H:%M:%S")
100	        .to_string();
101	
102	    let code_id = uuid::Uuid::new_v4().to_string();
103	    db::store_checkpoint_code(&state.db, &code_id, &req.fulfillment_id, req.checkpoint.as_str(), &code, &expires_at)
104	        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, Json(ApiError { error: e.to_string() })))?;
105	
