9	pub async fn donate(
10	    State(state): State<Arc<AppState>>,
11	    request: axum::http::Request<axum::body::Body>,
12	) -> Result<Json<DonateResponse>, (StatusCode, Json<ApiError>)> {
13	    let auth = require_auth(request.extensions())
14	        .map_err(|s| (s, Json(ApiError { error: "Unauthorized".into() })))?;
15	
16	    let body = axum::body::to_bytes(request.into_body(), 1_048_576)
17	        .await
18	        .map_err(|_| (StatusCode::BAD_REQUEST, Json(ApiError { error: "Invalid body".into() })))?;
19	    let req: DonateRequest = serde_json::from_slice(&body)
20	        .map_err(|e| (StatusCode::BAD_REQUEST, Json(ApiError { error: e.to_string() })))?;
21	
22	    if req.amount_cents <= 0 {
23	        return Err((
24	            StatusCode::BAD_REQUEST,
25	            Json(ApiError { error: "Donation amount must be positive".into() }),
26	        ));
27	    }
28	
29	    // Verify project exists and is active
30	    let project = db::get_project_detail(&state.db, &req.project_id).ok_or_else(|| {
31	        (StatusCode::NOT_FOUND, Json(ApiError { error: "Project not found".into() }))
32	    })?;
33	    if project.status != ProjectStatus::Active {
34	        return Err((
35	            StatusCode::BAD_REQUEST,
36	            Json(ApiError { error: "Project is not accepting donations".into() }),
37	        ));
38	    }
39	
40	    let payment_method = req.payment_method.as_deref().unwrap_or("cash");
41	    // Validate payment method
42	    if PaymentMethod::from_str(payment_method).is_none() {
43	        return Err((
44	            StatusCode::BAD_REQUEST,
45	            Json(ApiError { error: "Invalid payment method. Use: cash, check, card_terminal".into() }),
46	        ));
47	    }
48	
49	    // Validate budget line belongs to this project if specified
50	    if let Some(ref bl_id) = req.budget_line_id {
51	        let bl_project = db::get_budget_line_project_id(&state.db, bl_id)
52	            .ok_or_else(|| (StatusCode::NOT_FOUND, Json(ApiError { error: "Budget line not found".into() })))?;
53	        if bl_project != req.project_id {
54	            return Err((StatusCode::BAD_REQUEST, Json(ApiError {
55	                error: "Budget line does not belong to this project".into(),
56	            })));
57	        }
58	    }
59	
60	    let donation_id = uuid::Uuid::new_v4().to_string();
61	    let pledge_number = format!("PLG-{}", &donation_id[..8].to_uppercase());
62	
63	    db::create_donation(
64	        &state.db,
65	        &donation_id,
66	        &pledge_number,
67	        &req.project_id,
68	        &auth.user_id,
69	        req.amount_cents,
70	        payment_method,
71	        false,
72	        None,
73	        req.budget_line_id.as_deref(),
74	    )
75	    .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, Json(ApiError { error: e.to_string() })))?;
76	
77	    let donation = db::get_donation(&state.db, &donation_id).unwrap();
78	
79	    // Auto-subscribe donor to project notifications
80	    let _ = db::set_subscription(&state.db, &auth.user_id, &req.project_id, true);
81	
82	    db::append_ops_log(
83	        &state.db,
84	        &auth.user_id,
85	        "donor",
86	        "donate",
87	        &format!("Donated {} cents ({}) to project {}", req.amount_cents, payment_method, req.project_id),
88	    );
89	
90	    // Fire webhooks
91	    crate::routes::webhooks::fire_webhooks(
92	        &state,
93	        "donation.created",
94	        &serde_json::json!({
95	            "donation_id": donation_id,
96	            "project_id": req.project_id,
97	            "amount_cents": req.amount_cents,
98	            "payment_method": payment_method,
99	        }),
100	    )
101	    .await;
102	
103	    Ok(Json(DonateResponse { donation }))
104	}
