110	) -> Result<Json<DonateResponse>, (StatusCode, Json<ApiError>)> {
111	    let auth = require_auth(request.extensions())
112	        .map_err(|s| (s, Json(ApiError { error: "Unauthorized".into() })))?;
113	
114	    let body = axum::body::to_bytes(request.into_body(), 1_048_576)
115	        .await
116	        .map_err(|_| (StatusCode::BAD_REQUEST, Json(ApiError { error: "Invalid body".into() })))?;
117	    let req: RefundRequest = serde_json::from_slice(&body)
118	        .map_err(|e| (StatusCode::BAD_REQUEST, Json(ApiError { error: e.to_string() })))?;
119	
120	    // Get original donation
121	    let original = db::get_donation(&state.db, &req.donation_id).ok_or_else(|| {
122	        (StatusCode::NOT_FOUND, Json(ApiError { error: "Original donation not found".into() }))
123	    })?;
124	
125	    // Only the original donor may request a refund
126	    if original.donor_id != auth.user_id {
127	        return Err((StatusCode::FORBIDDEN, Json(ApiError {
128	            error: "Only the original donor can request a refund for this donation".into(),
129	        })));
130	    }
131	
132	    let reversal_id = uuid::Uuid::new_v4().to_string();
133	    let pledge_number = format!("REF-{}", &reversal_id[..8].to_uppercase());
134	
135	    db::create_donation(
136	        &state.db,
137	        &reversal_id,
138	        &pledge_number,
139	        &original.project_id,
140	        &original.donor_id,
141	        -original.amount_cents, // Negative amount
142	        &original.payment_method,
143	        true,
144	        Some(&req.donation_id),
145	        original.budget_line_id.as_deref(),
146	    )
147	    .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, Json(ApiError { error: e.to_string() })))?;
148	
149	    let reversal = db::get_donation(&state.db, &reversal_id).unwrap();
150	
