17	#[derive(Clone)]
18	pub struct RateLimitState {
19	    pub buckets: Arc<Mutex<HashMap<String, Vec<Instant>>>>,
20	    pub max_requests: usize,
21	    pub window_secs: u64,
22	}
23	
24	impl RateLimitState {
25	    pub fn new(max_requests: usize, window_secs: u64) -> Self {
26	        Self {
27	            buckets: Arc::new(Mutex::new(HashMap::new())),
28	            max_requests,
29	            window_secs,
30	        }
31	    }
32	
33	    pub fn check(&self, key: &str) -> bool {
34	        let mut buckets = self.buckets.lock();
35	        let now = Instant::now();
36	        let window = std::time::Duration::from_secs(self.window_secs);
37	        let entries = buckets.entry(key.to_string()).or_default();
38	        entries.retain(|t| now.duration_since(*t) < window);
39	        if entries.len() >= self.max_requests {
40	            false
41	        } else {
42	            entries.push(now);
43	            true
44	        }
45	    }
46	}
