48	/// Rate-limiting middleware: 60 requests per minute per session token (authenticated)
49	/// or per client IP (anonymous).
50	pub async fn rate_limit_middleware(
51	    State(state): State<Arc<AppState>>,
52	    headers: HeaderMap,
53	    request: Request,
54	    next: Next,
55	) -> Result<Response, StatusCode> {
56	    let key = if let Some(auth_val) = headers.get("authorization").and_then(|v| v.to_str().ok()) {
57	        auth_val.to_string()
58	    } else {
59	        // For anonymous requests, key by client IP from X-Forwarded-For or
60	        // X-Real-IP header, falling back to a per-request "anonymous" prefix.
61	        let ip = headers
62	            .get("x-forwarded-for")
63	            .and_then(|v| v.to_str().ok())
64	            .and_then(|v| v.split(',').next())
65	            .map(|s| s.trim().to_string())
66	            .or_else(|| {
67	                headers
68	                    .get("x-real-ip")
69	                    .and_then(|v| v.to_str().ok())
70	                    .map(|s| s.to_string())
71	            })
72	            .unwrap_or_else(|| "unknown".to_string());
73	        format!("anon:{}", ip)
74	    };
75	
76	    if !state.rate_limiter.check(&key) {
77	        return Err(StatusCode::TOO_MANY_REQUESTS);
78	    }
79	
80	    Ok(next.run(request).await)
81	}
