104	/// Nonce replay protection middleware.
105	pub async fn nonce_middleware(
106	    State(state): State<Arc<AppState>>,
107	    headers: HeaderMap,
108	    request: Request,
109	    next: Next,
110	) -> Result<Response, StatusCode> {
111	    // Only enforce nonce on mutating requests
112	    let method = request.method().clone();
113	    if method == axum::http::Method::GET || method == axum::http::Method::OPTIONS {
114	        return Ok(next.run(request).await);
115	    }
116	
117	    let nonce = headers.get("x-nonce").and_then(|v| v.to_str().ok());
118	    match nonce {
119	        Some(n) => {
120	            if !crate::db::consume_nonce(&state.db, n).unwrap_or(false) {
121	                return Err(StatusCode::CONFLICT); // Nonce already used or expired
122	            }
123	        }
124	        None => {
125	            // Nonce is mandatory for all mutating requests
126	            return Err(StatusCode::BAD_REQUEST);
127	        }
128	    }
129	
130	    Ok(next.run(request).await)
131	}
