9	/// Load or generate the application encryption key (32 bytes for AES-256).
10	/// Key path is resolved from ENCRYPTION_KEY_PATH env var,
11	/// defaulting to /var/lib/fund_transparency/encryption.key (host-managed, outside repo).
12	///
13	/// Returns an error instead of panicking when the key file is malformed or
14	/// unreadable, allowing the caller to log the problem and exit gracefully.
15	pub fn load_or_create_key() -> Result<[u8; 32], String> {
16	    let key_path = std::env::var("ENCRYPTION_KEY_PATH")
17	        .unwrap_or_else(|_| "/var/lib/fund_transparency/encryption.key".to_string());
18	    load_or_create_key_at(&key_path)
