21	pub fn load_or_create_key_at(key_path: &str) -> Result<[u8; 32], String> {
22	    let path = Path::new(key_path);
23	    if path.exists() {
24	        let data = std::fs::read(path).map_err(|e| {
25	            format!("Failed to read encryption key file '{}': {}", key_path, e)
26	        })?;
27	        if data.len() < 32 {
28	            return Err(format!(
29	                "Encryption key file '{}' is malformed: expected at least 32 bytes, got {}. \
30	                 Delete the file to auto-generate a new key, or provide a valid 32-byte key.",
31	                key_path, data.len()
32	            ));
33	        }
34	        let mut key = [0u8; 32];
35	        key.copy_from_slice(&data[..32]);
36	        Ok(key)
37	    } else {
38	        let key: [u8; 32] = rand::thread_rng().gen();
39	        if let Some(parent) = path.parent() {
40	            std::fs::create_dir_all(parent).ok();
41	        }
42	        std::fs::write(path, key).map_err(|e| {
43	            format!("Failed to write encryption key file '{}': {}", key_path, e)
44	        })?;
45	        Ok(key)
46	    }
47	}
48	
49	/// Encrypt plaintext using AES-256-GCM. Returns base64(nonce || ciphertext).
50	pub fn encrypt(plaintext: &str, key: &[u8; 32]) -> Result<String, String> {
51	    let cipher = Aes256Gcm::new_from_slice(key).map_err(|e| e.to_string())?;
52	    let nonce_bytes: [u8; 12] = rand::thread_rng().gen();
53	    let nonce = Nonce::from_slice(&nonce_bytes);
54	
55	    let ciphertext = cipher
56	        .encrypt(nonce, plaintext.as_bytes())
57	        .map_err(|e| e.to_string())?;
58	
59	    let mut combined = nonce_bytes.to_vec();
60	    combined.extend_from_slice(&ciphertext);
61	    Ok(STANDARD.encode(&combined))
62	}
63	
64	/// Encrypt raw bytes using AES-256-GCM. Returns nonce || ciphertext.
65	pub fn encrypt_bytes(plaintext: &[u8], key: &[u8; 32]) -> Result<Vec<u8>, String> {
66	    let cipher = Aes256Gcm::new_from_slice(key).map_err(|e| e.to_string())?;
67	    let nonce_bytes: [u8; 12] = rand::thread_rng().gen();
68	    let nonce = Nonce::from_slice(&nonce_bytes);
69	
70	    let ciphertext = cipher
71	        .encrypt(nonce, plaintext)
72	        .map_err(|e| e.to_string())?;
73	
74	    let mut combined = nonce_bytes.to_vec();
75	    combined.extend_from_slice(&ciphertext);
76	    Ok(combined)
77	}
78	
79	/// Decrypt raw bytes (nonce || ciphertext) using AES-256-GCM.
80	pub fn decrypt_bytes(encrypted: &[u8], key: &[u8; 32]) -> Result<Vec<u8>, String> {
81	    if encrypted.len() < 13 {
82	        return Err("Ciphertext too short".into());
83	    }
84	    let (nonce_bytes, ciphertext) = encrypted.split_at(12);
85	    let cipher = Aes256Gcm::new_from_slice(key).map_err(|e| e.to_string())?;
86	    let nonce = Nonce::from_slice(nonce_bytes);
87	
88	    cipher
89	        .decrypt(nonce, ciphertext)
90	        .map_err(|e| e.to_string())
91	}
92	
93	/// Decrypt base64(nonce || ciphertext) using AES-256-GCM.
94	pub fn decrypt(encoded: &str, key: &[u8; 32]) -> Result<String, String> {
95	    let combined = STANDARD.decode(encoded).map_err(|e| e.to_string())?;
96	    if combined.len() < 13 {
97	        return Err("Ciphertext too short".into());
98	    }
99	
100	    let (nonce_bytes, ciphertext) = combined.split_at(12);
101	    let cipher = Aes256Gcm::new_from_slice(key).map_err(|e| e.to_string())?;
102	    let nonce = Nonce::from_slice(nonce_bytes);
103	
104	    let plaintext = cipher
105	        .decrypt(nonce, ciphertext)
106	        .map_err(|e| e.to_string())?;
107	
108	    String::from_utf8(plaintext).map_err(|e| e.to_string())
109	}
