246	pub async fn export_csv(
247	    token: &str,
248	    from: Option<&str>,
249	    to: Option<&str>,
250	    cause: Option<&str>,
251	    status: Option<&str>,
252	) -> Result<String, String> {
253	    let mut parts = vec![];
254	    if let Some(f) = from { parts.push(format!("from={}", f)); }
255	    if let Some(t) = to { parts.push(format!("to={}", t)); }
256	    if let Some(c) = cause { parts.push(format!("cause={}", c)); }
257	    if let Some(s) = status { parts.push(format!("status={}", s)); }
258	    let q = if parts.is_empty() { String::new() } else { format!("?{}", parts.join("&")) };
259	    let mut req = Request::get(&format!("{}/admin/export/csv{}", BASE, q));
260	    req = req.header("Authorization", &format!("Bearer {}", token));
261	    let resp = req.send().await.map_err(|e| e.to_string())?;
262	    if !resp.ok() {
263	        return Err(resp.text().await.unwrap_or_default());
264	    }
265	    resp.text().await.map_err(|e| e.to_string())
266	}
