9	use crate::db;
10	use crate::middleware::{require_auth, require_role, require_project_owner};
11	use crate::AppState;
12	use common::*;
13	
14	pub async fn create_fulfillment(
15	    State(state): State<Arc<AppState>>,
16	    request: axum::http::Request<axum::body::Body>,
17	) -> Result<Json<FulfillmentRecord>, (StatusCode, Json<ApiError>)> {
18	    let auth = require_auth(request.extensions())
19	        .map_err(|s| (s, Json(ApiError { error: "Unauthorized".into() })))?;
20	    let _user = require_role(&state.db, &auth.user_id, &[Role::ProjectManager, Role::Administrator])
21	        .map_err(|s| (s, Json(ApiError { error: "Forbidden".into() })))?;
22	
23	    let body = axum::body::to_bytes(request.into_body(), 1_048_576)
24	        .await
25	        .map_err(|_| (StatusCode::BAD_REQUEST, Json(ApiError { error: "Invalid body".into() })))?;
26	
27	    #[derive(serde::Deserialize)]
28	    struct Req { project_id: String }
29	    let req: Req = serde_json::from_slice(&body)
30	        .map_err(|e| (StatusCode::BAD_REQUEST, Json(ApiError { error: e.to_string() })))?;
31	
32	    require_project_owner(&state.db, &auth.user_id, &req.project_id)
33	        .map_err(|s| (s, Json(ApiError { error: "You do not manage this project".into() })))?;
34	
35	    let id = uuid::Uuid::new_v4().to_string();
36	    db::create_fulfillment(&state.db, &id, &req.project_id)
37	        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, Json(ApiError { error: e.to_string() })))?;
