113	/// Record a checkpoint — ownership checked via fulfillment's project.
114	pub async fn record_checkpoint(
115	    State(state): State<Arc<AppState>>,
116	    request: axum::http::Request<axum::body::Body>,
117	) -> Result<Json<ApiSuccess>, (StatusCode, Json<ApiError>)> {
118	    let auth = require_auth(request.extensions())
119	        .map_err(|s| (s, Json(ApiError { error: "Unauthorized".into() })))?;
120	
121	    let body = axum::body::to_bytes(request.into_body(), 1_048_576)
122	        .await
123	        .map_err(|_| (StatusCode::BAD_REQUEST, Json(ApiError { error: "Invalid body".into() })))?;
124	    let req: RecordCheckpointRequest = serde_json::from_slice(&body)
125	        .map_err(|e| (StatusCode::BAD_REQUEST, Json(ApiError { error: e.to_string() })))?;
126	
127	    // Ownership check
128	    let project_id = db::get_fulfillment_project_id(&state.db, &req.fulfillment_id)
129	        .ok_or_else(|| (StatusCode::NOT_FOUND, Json(ApiError { error: "Fulfillment not found".into() })))?;
130	    require_project_owner(&state.db, &auth.user_id, &project_id)
131	        .map_err(|s| (s, Json(ApiError { error: "You do not manage this fulfillment's project".into() })))?;
132	
133	    // Validate code
134	    let valid = db::consume_checkpoint_code(&state.db, &req.fulfillment_id, req.checkpoint.as_str(), &req.code)
135	        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, Json(ApiError { error: e.to_string() })))?;
136	
137	    if !valid {
138	        return Err((StatusCode::BAD_REQUEST, Json(ApiError { error: "Invalid or expired code".into() })));
139	    }
140	
141	    let fulfillment = db::get_fulfillment(&state.db, &req.fulfillment_id)
142	        .ok_or_else(|| (StatusCode::NOT_FOUND, Json(ApiError { error: "Fulfillment not found".into() })))?;
143	
144	    let now = chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string();
145	
146	    // Time-consistency rules
147	    match req.checkpoint {
148	        CheckpointKind::Arrival => {}
149	        CheckpointKind::Start => {
150	            if let Some(ref arrival) = fulfillment.arrival_at {
151	                if let Ok(arrival_time) = chrono::NaiveDateTime::parse_from_str(arrival, "%Y-%m-%d %H:%M:%S") {
152	                    if let Ok(now_time) = chrono::NaiveDateTime::parse_from_str(&now, "%Y-%m-%d %H:%M:%S") {
153	                        let diff = now_time.signed_duration_since(arrival_time);
154	                        if diff.num_hours() > 2 {
155	                            return Err((StatusCode::BAD_REQUEST, Json(ApiError {
156	                                error: "Start must be within 2 hours of arrival".into()
157	                            })));
158	                        }
159	                    }
160	                }
161	            } else {
162	                return Err((StatusCode::BAD_REQUEST, Json(ApiError {
163	                    error: "Arrival must be recorded before start".into()
164	                })));
165	            }
166	        }
167	        CheckpointKind::End => {
168	            if let Some(ref start) = fulfillment.start_at {
169	                if let Ok(start_time) = chrono::NaiveDateTime::parse_from_str(start, "%Y-%m-%d %H:%M:%S") {
170	                    if let Ok(now_time) = chrono::NaiveDateTime::parse_from_str(&now, "%Y-%m-%d %H:%M:%S") {
171	                        if now_time <= start_time {
172	                            return Err((StatusCode::BAD_REQUEST, Json(ApiError {
173	                                error: "End timestamp must be strictly after start timestamp".into()
174	                            })));
175	                        }
176	                    }
177	                }
178	            } else {
179	                return Err((StatusCode::BAD_REQUEST, Json(ApiError {
180	                    error: "Start must be recorded before end".into()
181	                })));
182	            }
183	        }
184	    }
185	
186	    db::record_checkpoint(&state.db, &req.fulfillment_id, req.checkpoint.as_str(), &now)
187	        .map_err(|e| (StatusCode::INTERNAL_SERVER_ERROR, Json(ApiError { error: e.to_string() })))?;
188	
189	    if req.checkpoint == CheckpointKind::End {
190	        let updated = db::get_fulfillment(&state.db, &req.fulfillment_id).unwrap();
191	        if updated.arrival_at.is_some() && updated.start_at.is_some() && updated.end_at.is_some() {
192	            let record_data = format!(
193	                "{}|{}|{}|{}|{}",
194	                updated.id, updated.project_id,
195	                updated.arrival_at.as_deref().unwrap_or(""),
196	                updated.start_at.as_deref().unwrap_or(""),
197	                updated.end_at.as_deref().unwrap_or(""),
198	            );
199	            let mut hasher = Sha256::new();
200	            hasher.update(record_data.as_bytes());
201	            let hash = hex::encode(hasher.finalize());
202	            let _ = db::complete_fulfillment(&state.db, &req.fulfillment_id, &hash);
203	        }
204	    }
205	
206	    db::append_ops_log(&state.db, &auth.user_id, "user", "record_checkpoint",
207	        &format!("Recorded {} for fulfillment {}", req.checkpoint.as_str(), req.fulfillment_id));
208	
209	    Ok(Json(ApiSuccess { message: format!("Checkpoint {} recorded", req.checkpoint.as_str()) }))
210	}
211	
212	/// Service proof — scoped to project owner.
213	pub async fn service_proof(
214	    State(state): State<Arc<AppState>>,
215	    Path(fulfillment_id): Path<String>,
216	    request: axum::http::Request<axum::body::Body>,
217	) -> Result<Json<ServiceProof>, (StatusCode, Json<ApiError>)> {
218	    let auth = require_auth(request.extensions())
219	        .map_err(|s| (s, Json(ApiError { error: "Unauthorized".into() })))?;
220	    let f = db::get_fulfillment(&state.db, &fulfillment_id)
221	        .ok_or_else(|| (StatusCode::NOT_FOUND, Json(ApiError { error: "Fulfillment not found".into() })))?;
222	
223	    require_project_owner(&state.db, &auth.user_id, &f.project_id)
224	        .map_err(|s| (s, Json(ApiError { error: "Not authorized".into() })))?;
225	
226	    if !f.is_complete {
227	        return Err((StatusCode::BAD_REQUEST, Json(ApiError { error: "Fulfillment not yet complete".into() })));
228	    }
229	
230	    let project = db::get_project_detail(&state.db, &f.project_id)
231	        .ok_or_else(|| (StatusCode::NOT_FOUND, Json(ApiError { error: "Project not found".into() })))?;
232	
233	    Ok(Json(ServiceProof {
234	        fulfillment_id: f.id,
235	        project_id: f.project_id,
236	        project_title: project.title,
237	        arrival_at: f.arrival_at.unwrap_or_default(),
238	        start_at: f.start_at.unwrap_or_default(),
239	        end_at: f.end_at.unwrap_or_default(),
240	        service_record_hash: f.service_record_hash.unwrap_or_default(),
241	        generated_at: chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string(),
242	    }))
243	}
