10	pub async fn register(
11	    State(state): State<Arc<AppState>>,
12	    Json(req): Json<RegisterRequest>,
13	) -> Result<Json<AuthResponse>, (StatusCode, Json<ApiError>)> {
14	    if req.email.is_empty() || req.password.len() < 8 {
15	        return Err((
16	            StatusCode::BAD_REQUEST,
17	            Json(ApiError {
18	                error: "Email required and password must be at least 8 characters".into(),
19	            }),
20	        ));
21	    }
22	
23	    if db::get_user_by_email(&state.db, &req.email).is_some() {
24	        return Err((
25	            StatusCode::CONFLICT,
26	            Json(ApiError {
27	                error: "Email already registered".into(),
28	            }),
29	        ));
30	    }
31	
32	    let password_hash = hash_password(&req.password).map_err(|e| {
33	        (
34	            StatusCode::INTERNAL_SERVER_ERROR,
35	            Json(ApiError { error: e }),
36	        )
37	    })?;
38	
39	    let user_id = uuid::Uuid::new_v4().to_string();
40	    db::create_user(
41	        &state.db,
42	        &user_id,
43	        &req.email,
44	        &req.display_name,
45	        &password_hash,
46	        Role::Supporter.as_str(), // Always register as Supporter; roles are assigned by admins
47	    )
48	    .map_err(|e| {
49	        (
50	            StatusCode::INTERNAL_SERVER_ERROR,
51	            Json(ApiError {
52	                error: e.to_string(),
53	            }),
54	        )
55	    })?;
56	
57	    let token = create_session_token(&user_id, &state.hmac_secret, 86400);
58	    let user = db::get_user_by_id(&state.db, &user_id).unwrap();
59	
60	    db::append_ops_log(&state.db, &user_id, &req.display_name, "register", &format!("New user registered: {}", mask_email(&req.email)));
61	
62	    Ok(Json(AuthResponse { token, user }))
63	}
