136	/// Mask an email for logging: "john.doe@example.com" → "j***@example.com"
137	fn mask_email(email: &str) -> String {
138	    match email.split_once('@') {
139	        Some((local, domain)) => {
140	            let first = local.chars().next().unwrap_or('*');
141	            format!("{}***@{}", first, domain)
142	        }
143	        None => "***".to_string(),
144	    }
145	}
