152	    let (msg, set_msg) = create_signal(Option::<String>::None);
153	    let (comments_enabled, set_ce) = create_signal(true);
154	    let (pre_mod, set_pm) = create_signal(false);
155	    let (words, set_words) = create_signal(String::new());
156	
157	    // Load config on mount
158	    create_effect(move |_| {
159	        if let Some(token) = auth.get_token() {
160	            spawn_local(async move {
161	                if let Ok(c) = api::get_moderation_config(&token).await {
162	                    set_ce.set(c.comments_enabled);
163	                    set_pm.set(c.require_pre_moderation);
164	                    set_words.set(c.sensitive_words.join(", "));
165	                }
166	            });
167	        }
168	    });
169	
170	    let on_save = move |_| {
171	        if let Some(token) = auth.get_token() {
172	            let config = common::ModerationConfig {
173	                comments_enabled: comments_enabled.get(),
174	                require_pre_moderation: pre_mod.get(),
175	                sensitive_words: words.get().split(',').map(|s| s.trim().to_string()).filter(|s| !s.is_empty()).collect(),
176	            };
177	            spawn_local(async move {
178	                match api::update_moderation_config(&token, &config).await {
179	                    Ok(_) => set_msg.set(Some("Config saved".into())),
180	                    Err(e) => set_msg.set(Some(e)),
181	                }
182	            });
