202	#[component]
203	fn PendingRefunds() -> impl IntoView {
204	    let auth = use_context::<AuthState>().unwrap();
205	    let (refresh, set_refresh) = create_signal(0u32);
206	    let (pw, set_pw) = create_signal(String::new());
207	    let (msg, set_msg) = create_signal(Option::<String>::None);
208	
209	    let refunds = create_resource(
210	        move || (auth.get_token(), refresh.get()),
211	        |(token, _)| async move {
212	            match token {
213	                Some(t) => api::pending_refunds(&t).await.ok(),
214	                None => None,
215	            }
216	        },
217	    );
218	
219	    // Two-step confirmation state: stores (donation_id, approved) pending confirmation
220	    let (confirm_action, set_confirm_action) = create_signal(Option::<(String, bool)>::None);
221	
222	    let do_approve = move |donation_id: String, approved: bool| {
223	        // Step 1: require user to click first to enter confirmation state
224	        let current = confirm_action.get();
225	        if current.as_ref().map_or(true, |c| c.0 != donation_id || c.1 != approved) {
226	            set_confirm_action.set(Some((donation_id, approved)));
227	            set_msg.set(Some("Please re-enter your password and click again to confirm.".into()));
228	            return;
229	        }
230	
231	        // Step 2: actually submit with password
232	        if let Some(token) = auth.get_token() {
233	            let password = pw.get();
234	            if password.is_empty() {
235	                set_msg.set(Some("Password is required to confirm this action".into()));
236	                return;
237	            }
238	            set_confirm_action.set(None);
239	            spawn_local(async move {
240	                match api::approve_refund(&token, &donation_id, approved, &password).await {
241	                    Ok(r) => {
242	                        set_msg.set(Some(r.message));
243	                        set_refresh.update(|c| *c += 1);
244	                    }
245	                    Err(e) => set_msg.set(Some(e)),
246	                }
247	            });
248	        }
249	    };
250	
251	    view! {
252	        {move || msg.get().map(|m| view! { <div class="info-msg">{m}</div> })}
253	        {move || confirm_action.get().map(|(ref id, approved)| {
254	            let action = if approved { "approve" } else { "reject" };
255	            view! {
256	                <div class="confirm-box">
257	                    <p class="warning">{format!("You are about to {} refund {}. Enter your password and click the button again to confirm.", action, id)}</p>
258	                </div>
259	            }
260	        })}
261	        <div class="form-group">
262	            <label>"Password (required for refund approval)"</label>
263	            <input type="password" placeholder="Re-enter password"
264	                on:input=move |ev| set_pw.set(event_target_value(&ev))
265	                prop:value=pw />
266	        </div>
267	        <Suspense fallback=move || view! { <p>"Loading..."</p> }>
268	            {move || refunds.get().map(|data| match data {
269	                Some(list) if !list.is_empty() => {
270	                    view! {
271	                        <div class="expense-review-list">
272	                            {list.into_iter().map(|d| {
273	                                let did_a = d.id.clone();
274	                                let did_r = d.id.clone();
275	                                let is_confirming_approve = {
276	                                    let did = d.id.clone();
277	                                    move || confirm_action.get().map_or(false, |c| c.0 == did && c.1)
278	                                };
279	                                let is_confirming_reject = {
280	                                    let did = d.id.clone();
281	                                    move || confirm_action.get().map_or(false, |c| c.0 == did && !c.1)
282	                                };
283	                                view! {
284	                                    <div class="expense-card">
285	                                        <div class="expense-header">
286	                                            <strong>{d.pledge_number.clone()}</strong>
287	                                            <span class="amount">{format!("${:.2}", d.amount_cents as f64 / 100.0)}</span>
288	                                        </div>
289	                                        <div class="expense-meta">
290	                                            <span>"Project: " {d.project_title.clone()}</span>
291	                                            <span>"Method: " {d.payment_method.clone()}</span>
292	                                            <span>"Original: " {d.reversal_of.clone().unwrap_or_default()}</span>
293	                                        </div>
294	                                        <div class="review-actions">
295	                                            <button class="btn btn-success"
296	                                                on:click={let f = do_approve.clone(); move |_| f(did_a.clone(), true)}>
297	                                                {move || if is_confirming_approve() { "Confirm Approve" } else { "Approve Refund" }}
298	                                            </button>
299	                                            <button class="btn btn-danger"
300	                                                on:click={let f = do_approve.clone(); move |_| f(did_r.clone(), false)}>
301	                                                {move || if is_confirming_reject() { "Confirm Reject" } else { "Reject" }}
302	                                            </button>
303	                                        </div>
304	                                    </div>
305	                                }
306	                            }).collect::<Vec<_>>()}
307	                        </div>
308	                    }.into_view()
309	                }
