252	#[component]
253	fn ReceiptUploadForm() -> impl IntoView {
254	    let auth = use_context::<AuthState>().unwrap();
255	    let (expense_id, set_expense_id) = create_signal(String::new());
256	    let (file_data, set_file_data) = create_signal(Option::<(String, String, i64, String)>::None); // (name, type, size, base64)
257	    let (upload_msg, set_upload_msg) = create_signal(Option::<String>::None);
258	
259	    let on_file_change = move |ev: leptos::ev::Event| {
260	        use wasm_bindgen::JsCast;
261	        let input: web_sys::HtmlInputElement = ev.target().unwrap().unchecked_into();
262	        if let Some(files) = input.files() {
263	            if let Some(file) = files.get(0) {
264	                let name = file.name();
265	                let mime = file.type_();
266	                let size = file.size() as i64;
267	
268	                // Validate type
269	                let allowed = ["application/pdf", "image/jpeg", "image/png"];
270	                if !allowed.contains(&mime.as_str()) {
271	                    set_upload_msg.set(Some(format!("Invalid file type: {}. Use PDF, JPG, or PNG.", mime)));
272	                    return;
273	                }
274	                // Validate size (10 MB)
275	                if size > 10 * 1024 * 1024 {
276	                    set_upload_msg.set(Some("File too large. Maximum 10 MB.".into()));
277	                    return;
278	                }
279	
280	                let reader = web_sys::FileReader::new().unwrap();
281	                let reader_clone = reader.clone();
282	                let closure = wasm_bindgen::closure::Closure::wrap(Box::new(move |_: web_sys::Event| {
283	                    if let Ok(result) = reader_clone.result() {
284	                        let data_url: String = result.as_string().unwrap_or_default();
285	                        // Strip data URL prefix to get base64
286	                        let base64 = data_url.split(',').nth(1).unwrap_or("").to_string();
287	                        set_file_data.set(Some((name.clone(), mime.clone(), size, base64)));
288	                    }
289	                }) as Box<dyn FnMut(_)>);
290	                reader.set_onload(Some(closure.as_ref().unchecked_ref()));
291	                closure.forget();
292	                let _ = reader.read_as_data_url(&file);
293	            }
294	        }
295	    };
296	
297	    let on_upload = move |_| {
298	        if let (Some(token), Some((name, mime, size, b64))) = (auth.get_token(), file_data.get()) {
299	            let eid = expense_id.get();
300	            if eid.is_empty() {
301	                set_upload_msg.set(Some("Enter expense ID".into()));
302	                return;
303	            }
304	            let req = common::UploadReceiptRequest {
305	                expense_id: eid,
306	                file_name: name,
307	                file_type: mime,
308	                file_size: size,
309	                file_data_base64: b64,
310	            };
311	            spawn_local(async move {
312	                match api::upload_receipt(&token, &req).await {
313	                    Ok(r) => set_upload_msg.set(Some(format!("Receipt uploaded: {} (SHA256: {})", r.file_name, &r.sha256_fingerprint[..16]))),
314	                    Err(e) => set_upload_msg.set(Some(e)),
315	                }
316	            });
317	        } else {
318	            set_upload_msg.set(Some("Select a file first".into()));
319	        }
320	    };
321	
322	    view! {
323	        {move || upload_msg.get().map(|m| view! { <div class="info-msg">{m}</div> })}
324	        <div class="form-row">
325	            <div class="form-group">
326	                <label>"Expense ID"</label>
327	                <input type="text" on:input=move |ev| set_expense_id.set(event_target_value(&ev)) prop:value=expense_id />
328	            </div>
329	            <div class="form-group">
330	                <label>"Receipt File (PDF/JPG/PNG, max 10 MB)"</label>
331	                <input type="file" accept=".pdf,.jpg,.jpeg,.png" on:change=on_file_change />
332	            </div>
333	            <button class="btn btn-secondary" on:click=on_upload>"Upload Receipt"</button>
334	        </div>
335	    }
336	}
