339	fn TicketResponsePanel() -> impl IntoView {
340	    let auth = use_context::<AuthState>().unwrap();
341	    let (project_id, set_project_id) = create_signal(String::new());
342	    let (refresh, set_refresh) = create_signal(0u32);
343	    let (resp_text, set_resp_text) = create_signal(String::new());
344	    let (msg, set_msg) = create_signal(Option::<String>::None);
345	
346	    let tickets = create_resource(
347	        move || (auth.get_token(), project_id.get(), refresh.get()),
348	        |(token, pid, _)| async move {
349	            if pid.is_empty() { return None; }
350	            match token {
351	                Some(t) => api::list_tickets(&t, &pid).await.ok(),
352	                None => None,
353	            }
354	        },
355	    );
356	
357	    let on_respond = move |ticket_id: String| {
358	        if let Some(token) = auth.get_token() {
359	            let response = resp_text.get();
360	            if response.is_empty() {
361	                set_msg.set(Some("Enter a response".into()));
362	                return;
363	            }
364	            spawn_local(async move {
365	                match api::respond_ticket(&token, &ticket_id, &response).await {
366	                    Ok(r) => {
367	                        set_msg.set(Some(r.message));
368	                        set_resp_text.set(String::new());
369	                        set_refresh.update(|c| *c += 1);
370	                    }
371	                    Err(e) => set_msg.set(Some(e)),
372	                }
373	            });
374	        }
375	    };
376	
377	    view! {
378	        {move || msg.get().map(|m| view! { <div class="info-msg">{m}</div> })}
379	        <div class="form-row">
380	            <div class="form-group">
381	                <label>"Project ID"</label>
382	                <input type="text" placeholder="Enter project ID to load tickets"
383	                    on:input=move |ev| { set_project_id.set(event_target_value(&ev)); set_refresh.update(|c| *c += 1); }
384	                    prop:value=project_id />
385	            </div>
386	        </div>
387	        <div class="form-group">
388	            <label>"Response text"</label>
389	            <textarea placeholder="Type your response..."
390	                on:input=move |ev| set_resp_text.set(event_target_value(&ev))
391	                prop:value=resp_text />
392	        </div>
393	        <Suspense fallback=move || view! { <p>"Enter a project ID above..."</p> }>
394	            {move || tickets.get().map(|data| match data {
395	                Some(list) if !list.is_empty() => {
396	                    view! {
397	                        <div class="expense-review-list">
398	                            {list.into_iter().map(|t| {
399	                                let tid = t.id.clone();
400	                                let has_response = t.response.is_some();
401	                                view! {
402	                                    <div class="expense-card">
403	                                        <div class="expense-header">
404	                                            <strong>{t.subject.clone()}</strong>
405	                                            <span class="badge">{t.status.clone()}</span>
406	                                        </div>
407	                                        <p>{t.body.clone()}</p>
408	                                        <div class="expense-meta">
409	                                            <span>"From: " {t.submitter_name.clone()}</span>
410	                                            <span>{t.created_at.clone()}</span>
411	                                        </div>
412	                                        {t.response.as_ref().map(|r| view! {
413	                                            <div class="info-msg">"Response: " {r.clone()}</div>
414	                                        })}
415	                                        {(!has_response).then(|| {
416	                                            let on_respond = on_respond.clone();
417	                                            view! {
418	                                                <button class="btn btn-primary btn-sm"
419	                                                    on:click=move |_| on_respond(tid.clone())>
420	                                                    "Send Response"
421	                                                </button>
422	                                            }
423	                                        })}
424	                                    </div>
425	                                }
426	                            }).collect::<Vec<_>>()}
427	                        </div>
428	                    }.into_view()
429	                }
430	                _ => view! { <p class="empty">"No tickets found."</p> }.into_view(),
431	            })}
432	        </Suspense>
433	    }
434	}
