1	/* ── Reset & Base ── */
2	*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
3	:root {
4	    --primary: #2563eb;
5	    --primary-hover: #1d4ed8;
6	    --secondary: #64748b;
7	    --success: #16a34a;
8	    --danger: #dc2626;
9	    --warning: #f59e0b;
10	    --bg: #f8fafc;
11	    --surface: #ffffff;
12	    --text: #1e293b;
13	    --text-muted: #64748b;
14	    --border: #e2e8f0;
15	    --radius: 8px;
16	}
17	body {
18	    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
19	    background: var(--bg);
20	    color: var(--text);
21	    line-height: 1.6;
22	}
23	a { color: var(--primary); text-decoration: none; }
24	a:hover { text-decoration: underline; }
25	
26	/* ── Container ── */
27	.container { max-width: 1200px; margin: 0 auto; padding: 2rem 1rem; }
28	
29	/* ── Navbar ── */
30	.navbar {
31	    display: flex; align-items: center; justify-content: space-between;
32	    padding: 1rem 2rem; background: var(--surface); border-bottom: 1px solid var(--border);
33	    position: sticky; top: 0; z-index: 100;
34	}
35	.nav-brand a { font-size: 1.25rem; font-weight: 700; color: var(--primary); text-decoration: none; }
36	.nav-links { display: flex; align-items: center; gap: 1.25rem; }
37	.nav-links a { color: var(--text); font-weight: 500; }
38	.nav-links a:hover { color: var(--primary); }
39	.btn-nav-logout {
40	    background: none; border: 1px solid var(--danger); color: var(--danger);
41	    padding: .35rem .75rem; border-radius: var(--radius); cursor: pointer; font-size: .875rem;
42	}
43	.btn-nav-logout:hover { background: var(--danger); color: #fff; }
44	
45	/* ── Buttons ── */
46	.btn {
47	    display: inline-block; padding: .6rem 1.25rem; border-radius: var(--radius);
48	    font-weight: 600; font-size: .9rem; border: none; cursor: pointer;
49	    text-align: center; transition: all .15s; text-decoration: none;
50	}
51	.btn-primary { background: var(--primary); color: #fff; }
52	.btn-primary:hover { background: var(--primary-hover); }
53	.btn-secondary { background: var(--surface); color: var(--text); border: 1px solid var(--border); }
54	.btn-secondary:hover { background: var(--bg); }
55	.btn-success { background: var(--success); color: #fff; }
56	.btn-success:hover { opacity: .9; }
57	.btn-danger { background: var(--danger); color: #fff; }
58	.btn-danger:hover { opacity: .9; }
59	.btn-sm { padding: .35rem .75rem; font-size: .8rem; }
60	.btn-lg { padding: .8rem 2rem; font-size: 1.1rem; }
61	.btn:disabled { opacity: .5; cursor: not-allowed; }
62	
63	/* ── Hero ── */
64	.hero { text-align: center; padding: 4rem 1rem; }
65	.hero h1 { font-size: 2.5rem; margin-bottom: 1rem; color: var(--text); }
66	.subtitle { font-size: 1.15rem; color: var(--text-muted); max-width: 700px; margin: 0 auto 2rem; }
67	.hero-actions { display: flex; gap: 1rem; justify-content: center; }
68	
69	/* ── Features ── */
70	.features { display: grid; grid-template-columns: repeat(auto-fit, minmax(250px, 1fr)); gap: 1.5rem; margin-top: 3rem; }
71	.feature-card {
72	    background: var(--surface); padding: 2rem; border-radius: var(--radius);
73	    border: 1px solid var(--border);
74	}
75	.feature-card h3 { margin-bottom: .5rem; color: var(--primary); }
76	
77	/* ── Auth Pages ── */
78	.auth-page { max-width: 420px; margin: 2rem auto; }
79	.auth-page h2 { margin-bottom: 1.5rem; }
80	.auth-switch { margin-top: 1rem; color: var(--text-muted); }
81	
82	/* ── Forms ── */
83	.form-group { margin-bottom: 1rem; }
84	.form-group label { display: block; font-weight: 600; margin-bottom: .35rem; font-size: .9rem; }
85	.form-group input, .form-group select, .form-group textarea {
86	    width: 100%; padding: .6rem .75rem; border: 1px solid var(--border);
87	    border-radius: var(--radius); font-size: .95rem; background: var(--surface);
