                                    })
                                }}
                            </a>
                            {is_staff.then(|| view! { <a href="/staff">"Staff Ops"</a> })}
                        {is_staff.then(|| view! { <a href="/dashboard">"Dashboard"</a> })}
                            {is_finance.then(|| view! { <a href="/finance">"Finance"</a> })}
                            {is_admin.then(|| view! { <a href="/admin">"Admin"</a> })}
