11	pub fn ProjectDetailPage() -> impl IntoView {
12	    let params = use_params_map();
13	    let auth = use_context::<AuthState>().unwrap();
14	
15	    let project_id = move || params.with(|p| p.get("id").cloned().unwrap_or_default());
16	
17	    // Track impression and dwell time
18	    let entered_at = std::rc::Rc::new(std::cell::Cell::new(js_sys::Date::now() as i64));
19	    {
20	        let entered_at = entered_at.clone();
21	        let project_id = project_id.clone();
22	        create_effect(move |_| {
23	            let pid = project_id();
24	            if !pid.is_empty() {
25	                analytics::emit(common::EventKind::Impression, "project", &pid);
26	                entered_at.set(js_sys::Date::now() as i64);
27	            }
28	        });
29	    }
30	    {
31	        let entered_at = entered_at.clone();
32	        on_cleanup(move || {
33	            let pid = project_id();
34	            if !pid.is_empty() {
35	                let dwell = js_sys::Date::now() as i64 - entered_at.get();
36	                analytics::emit_dwell(common::EventKind::DwellTime, "project", &pid, dwell);
37	            }
38	        });
39	    }
40	
41	    let project = create_resource(project_id, |id| async move {
42	        api::get_project(&id).await.ok()
43	    });
44	
45	    let on_favorite = move |_| {
46	        let id = project_id();
47	        analytics::emit(common::EventKind::Click, "favorite", &id);
48	        if let Some(token) = auth.get_token() {
49	            spawn_local(async move {
50	                let _ = api::toggle_favorite(&token, &id).await;
51	            });
52	        }
53	    };
54	
55	    let on_subscribe = move |_| {
56	        if let Some(token) = auth.get_token() {
57	            let id = project_id();
58	            spawn_local(async move {
59	                let _ = api::subscribe(&token, &id).await;
60	            });
61	        }
62	    };
63	
64	    let on_unsubscribe = move |_| {
65	        if let Some(token) = auth.get_token() {
66	            let id = project_id();
67	            spawn_local(async move {
68	                let _ = api::unsubscribe(&token, &id).await;
69	            });
70	        }
71	    };
72	
73	    view! {
74	        <Suspense fallback=move || view! { <p>"Loading project..."</p> }>
75	            {move || project.get().map(|data| match data {
76	                Some(p) => {
77	                    let pid = p.id.clone();
78	                    let budget_lines = p.budget_lines.clone();
79	                    let updates = p.updates.clone();
80	                    view! {
81	                        <div class="project-detail">
82	                            <div class="project-header">
83	                                <h2>{&p.title}</h2>
84	                                <div class="project-meta">
85	                                    <span class="badge">{p.status.as_str()}</span>
86	                                    <span class="cause-tag">{&p.cause}</span>
87	                                    <span class="zip-tag">{&p.zip_code}</span>
88	                                    <span class="manager">"By: " {&p.manager_name}</span>
89	                                </div>
90	                            </div>
91	
92	                            <div class="project-body">
93	                                <p class="description">{&p.description}</p>
94	
95	                                <div class="overall-progress">
96	                                    <h3>"Fundraising Progress"</h3>
97	                                    <BudgetBar label="Total Raised".to_string()
98	                                        current=p.raised_cents max=p.goal_cents />
99	                                    <BudgetBar label="Total Spent (Verified)".to_string()
100	                                        current=p.spent_cents max=p.raised_cents.max(1) />
101	                                </div>
102	
103	                                <div class="budget-section">
104	                                    <h3>"Budget Breakdown"</h3>
105	                                    {budget_lines.into_iter().map(|bl| {
106	                                        let name = bl.name.clone();
107	                                        view! {
108	                                            <BudgetBar label=name
109	                                                current=bl.spent_cents max=bl.allocated_cents />
110	                                        }
111	                                    }).collect::<Vec<_>>()}
112	                                </div>
113	
114	                                <div class="action-buttons">
115	                                    <a href=format!("/donate/{}", &pid) class="btn btn-primary">
116	                                        "Donate to This Project"
117	                                    </a>
118	                                    <button class="btn btn-secondary" on:click=on_favorite>
119	                                        "Favorite"
120	                                    </button>
121	                                    <button class="btn btn-secondary" on:click=on_subscribe>
122	                                        "Subscribe"
123	                                    </button>
124	                                    <button class="btn btn-secondary" on:click=on_unsubscribe>
125	                                        "Unsubscribe"
126	                                    </button>
127	                                </div>
128	
129	                                <div class="updates-section">
130	                                    <h3>"Spending Updates"</h3>
131	                                    {if updates.is_empty() {
132	                                        view! { <p class="empty">"No updates yet."</p> }.into_view()
133	                                    } else {
134	                                        updates.into_iter().map(|u| {
135	                                            let uid = u.id.clone();
136	                                            let on_like = move |_| {
137	                                                let uid = uid.clone();
138	                                                if let Some(token) = auth.get_token() {
139	                                                    spawn_local(async move {
140	                                                        let _ = api::toggle_like(&token, &uid).await;
141	                                                    });
142	                                                }
143	                                            };
144	                                            view! {
145	                                                <div class="update-card">
146	                                                    <h4>{&u.title}</h4>
147	                                                    <p>{&u.body}</p>
148	                                                    <div class="update-meta">
149	                                                        <span>"By " {&u.author_name}</span>
150	                                                        <span>{&u.created_at}</span>
151	                                                        <button class="btn-like" on:click=on_like>
152	                                                            {format!("Like ({})", u.like_count)}
153	                                                        </button>
154	                                                    </div>
155	                                                </div>
156	                                            }
157	                                        }).collect::<Vec<_>>().into_view()
158	                                    }}
159	                                </div>
160	
161	                                <CommentSection project_id=pid />
162	                            </div>
163	                        </div>
164	                    }.into_view()
165	                }
166	                None => view! { <p>"Project not found."</p> }.into_view(),
167	            })}
168	        </Suspense>
169	    }
170	}
