pub fn RegisterPage() -> impl IntoView {
    let auth = use_context::<AuthState>().unwrap();
    let (email, set_email) = create_signal(String::new());
    let (password, set_password) = create_signal(String::new());
    let (name, set_name) = create_signal(String::new());
    let (error, set_error) = create_signal(Option::<String>::None);
    let navigate = use_navigate();

    let on_submit = move |ev: leptos::ev::SubmitEvent| {
        ev.prevent_default();
        let email = email.get();
        let password = password.get();
        let name = name.get();
        let navigate = navigate.clone();
        spawn_local(async move {
            match api::register(&email, &password, &name, common::Role::Supporter).await {
                Ok(resp) => {
                    auth.login(resp.token, resp.user);
                    navigate("/projects", Default::default());
                }
                Err(e) => set_error.set(Some(e)),
            }
        });
    };

    view! {
        <div class="auth-page">
            <h2>"Create Account"</h2>
            {move || error.get().map(|e| view! { <div class="error-msg">{e}</div> })}
            <form on:submit=on_submit>
                <div class="form-group">
                    <label>"Display Name"</label>
                    <input type="text" required
                        on:input=move |ev| set_name.set(event_target_value(&ev))
                        prop:value=name />
                </div>
                <div class="form-group">
                    <label>"Email"</label>
                    <input type="email" required
                        on:input=move |ev| set_email.set(event_target_value(&ev))
                        prop:value=email />
                </div>
                <div class="form-group">
                    <label>"Password (min 8 characters)"</label>
                    <input type="password" required minlength="8"
                        on:input=move |ev| set_password.set(event_target_value(&ev))
                        prop:value=password />
                </div>
